public class ThreadTest {
    public static void main(String[] args) {
        Thread odd = new Thread(() -> {
            for (int i=1;i<=10;i+=2) System.out.println(Thread.currentThread().getName()+": "+i);
        }, "奇数线程");
        Thread even = new Thread(() -> {
            for (int i=2;i<=10;i+=2) System.out.println(Thread.currentThread().getName()+": "+i);
        }, "偶数线程");
        odd.start(); even.start();
        try { odd.join(); even.join(); } catch (Exception e) {}
        System.out.println("end");
    }
}
